package com.example.socialmediacampaignagentsprintboot.agent;import com.example.socialmediacampaignagentsprintboot.model.ContentPillar;import com.example.socialmediacampaignagentsprintboot.model.FunnelStage;import com.example.socialmediacampaignagentsprintboot.model.Platform;import dev.langchain4j.service.SystemMessage;import dev.langchain4j.service.UserMessage;import dev.langchain4j.service.V;public interface CopywriterAgent {    @SystemMessage("""        You are an expert Social Media Copywriter.        Your goal is to write a single post based on specific strategic directives.                INSTRUCTIONS:        - Use the 'FunnelStage' to decide how salesy to be (e.g. Awareness = Helpful, Conversion = Urgent).        - Use the 'ContentPillar' to decide the angle (e.g. Education = Teach, Behind-the-Scenes = Personal).                CRITICAL PLATFORM RULES:        1. LinkedIn:        - Professional but engaging tone.        - Use lists/bullet points if needed.        - Length: 500-1500 characters.        2. X:        - Casual, punchy tone.        - ABSOLUTE HARD LIMIT: 280 CHARACTERS MAX (including hashtags and spaces).        - PREFER: Under 200 characters for better engagement.        - If the topic is complex, summarize it into a "hook" rather than explaining everything.                OUTPUT FORMAT:        Return ONLY the post text.        """)    @UserMessage("""        Context:        - Platform: {{platform}}        - Target Audience: {{audience}}        - Funnel Stage: {{funnelStage}}        - Content Pillar: {{contentPillar}}                Directive:        Write a post about: {{topicSummary}}        """)    String writePost(@V("platform") Platform platform,                     @V("audience") String audience,                     @V("funnelStage") FunnelStage funnelStage,                     @V("contentPillar") ContentPillar contentPillar,                     @V("topicSummary") String topicSummary);    @UserMessage("""        The following draft you wrote for {{platform}} was REJECTED by the quality assurance reviewer.                [REJECTED DRAFT]:        {{previousDraft}}                [REVIEWER FEEDBACK]:        {{feedback}}        Please rewrite the post to fix these exact issues.        Return ONLY the new post text.        """)    String rewritePost(@V("platform") Platform platform,                       @V("previousDraft") String previousDraft,                       @V("feedback") String feedback);    @SystemMessage("""        You are a strict social media editor.        Rewrite the following draft based strictly on the user's instruction.                CRITICAL PLATFORM RULES TO MAINTAIN:        1. LinkedIn: Professional but engaging tone. Length: 500-1500 characters.        2. X: Casual, punchy tone. ABSOLUTE HARD LIMIT: 280 CHARACTERS MAX (including spaces).                OUTPUT FORMAT:        Return ONLY the rewritten post text. Do not include introductory text or quotes.        """)    @UserMessage("""        Platform: {{platform}}                [CURRENT DRAFT]:        {{draft}}                [HUMAN INSTRUCTION]:        {{instruction}}                Return ONLY the rewritten post text. Do not include introductory text or quotes.        """)    String revisePost(@V("platform") Platform platform, @V("draft") String draft, @V("instruction") String instruction);}